import React from "react";
import "./Products.css";

function Products({ addToCart, search, category }) {

  // ✅ Product Data (with category added)
  const products = [
    {
      name: "iPhone 14",
      category: "Mobiles",
      price: "₹70,000",
      discount: "10% off",
      img: "https://images.unsplash.com/photo-1592750475338-74b7b21085ab?w=200"
    },
    {
      name: "Nike Shoes",
      category: "Fashion",
      price: "₹2,000",
      discount: "20% off",
      img: "https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=200"
    },
    {
      name: "Headphones",
      category: "Electronics",
      price: "₹1,500",
      discount: "15% off",
      img: "https://images.unsplash.com/photo-1518444065439-e933c06ce9cd?w=200"
    },
    {
      name: "Smart TV",
      category: "Electronics",
      price: "₹30,000",
      discount: "25% off",
      img: "https://images.unsplash.com/photo-1593784991095-a205069470b6?w=200"
    },
    {
      name: "Sofa",
      category: "Home",
      price: "₹15,000",
      discount: "30% off",
      img: "https://images.unsplash.com/photo-1586023492125-27b2c045efd7?w=200"
    },
    {
      name: "Face Wash",
      category: "Beauty",
      price: "₹300",
      discount: "5% off",
      img: "https://encrypted-tbn1.gstatic.com/shopping?q=tbn:ANd9GcTyFTntOymx8NSz44HOMwJwrpSk7J3Gk3aOCO-8viskNweAbbuLLfwmCMHz8cH9uoDicrRC6oZNJDlSp3CZP2m9ycVpyxS7q8pQ1j_Fzis1TvxiPx08vJx1jN0"
    }
  ];

  const filtered = products.filter((item) => {
    return (
      item.name.toLowerCase().includes(search.toLowerCase()) &&
      (category === "All" || item.category === category)
    );
  });

  return (
    <div className="products">
      {filtered.map((item, index) => (
        <div className="product-card" key={index}>
          <img src={item.img} alt={item.name} />
          <h4>{item.name}</h4>
          <p className="price">{item.price}</p>
          <p className="discount">{item.discount}</p>

          <button onClick={() => addToCart(item)}>
            Add to Cart
          </button>
        </div>
      ))}
    </div>
  );
}

export default Products;
